'use client';

import * as React from 'react';
import { Clock } from 'lucide-react';
import { Popover, PopoverTrigger, PopoverContent } from '@/components/ui/popover';
import { ScrollArea } from '@/components/ui/scroll-area';
import { cn } from '@/lib/utils';

export interface TimeSelectorProps {
  value?: string; // Format "HH:MM"
  onChange?: (value: string) => void;
  className?: string;
  placeholder?: string;
  disabled?: boolean;
  id?: string;
  name?: string;
}

export const TimeSelector = React.forwardRef<HTMLButtonElement, TimeSelectorProps>(
  ({ value, onChange, className, placeholder = '00:00', disabled = false, id, name }, ref) => {
    const [isOpen, setIsOpen] = React.useState(false);
    const [hour, setHour] = React.useState<string>('12');
    const [minute, setMinute] = React.useState<string>('00');

    const activeHourRef = React.useRef<HTMLButtonElement>(null);
    const activeMinuteRef = React.useRef<HTMLButtonElement>(null);

    // Sync state when value changes
    React.useEffect(() => {
      if (value) {
        const [h, m] = value.split(':');
        if (h && m) {
          setHour(h);
          setMinute(m);
        }
      }
    }, [value]);

    // Scroll selected items into view when popover opens
    React.useEffect(() => {
      if (isOpen) {
        const timer = setTimeout(() => {
          activeHourRef.current?.scrollIntoView({ block: 'center', behavior: 'auto' });
          activeMinuteRef.current?.scrollIntoView({ block: 'center', behavior: 'auto' });
        }, 80); // Small timeout to ensure DOM layout is complete
        return () => clearTimeout(timer);
      }
    }, [isOpen]);

    const hours = Array.from({ length: 24 }, (_, i) => i.toString().padStart(2, '0'));
    const minutes = Array.from({ length: 60 }, (_, i) => i.toString().padStart(2, '0'));

    const handleSelectHour = (selectedHour: string) => {
      setHour(selectedHour);
      if (onChange) {
        onChange(`${selectedHour}:${minute}`);
      }
    };

    const handleSelectMinute = (selectedMinute: string) => {
      setMinute(selectedMinute);
      if (onChange) {
        onChange(`${hour}:${selectedMinute}`);
      }
    };

    return (
      <Popover open={isOpen} onOpenChange={setIsOpen}>
        <PopoverTrigger asChild>
          <button
            type="button"
            ref={ref}
            id={id}
            name={name}
            disabled={disabled}
            className={cn(
              'flex h-10 w-full items-center justify-between rounded-xl border border-border bg-background px-3 py-2 text-sm text-foreground shadow-sm transition-all focus:outline-none focus:ring-1 focus:ring-ring disabled:cursor-not-allowed disabled:opacity-50 text-left hover:bg-accent/50',
              className
            )}
          >
            <span className="flex items-center gap-2">
              <Clock className="h-4 w-4 text-muted-foreground shrink-0" />
              <span>{value || placeholder}</span>
            </span>
          </button>
        </PopoverTrigger>

        <PopoverContent className="w-[180px] p-2" align="start">
          <div className="grid grid-cols-2 gap-2 text-center text-xs font-bold text-muted-foreground border-b pb-1.5 mb-1">
            <div>Hora</div>
            <div>Min.</div>
          </div>

          <div className="grid grid-cols-2 gap-1.5 h-60">
            {/* Hours scroll container */}
            <ScrollArea className="h-full pr-1">
              <div className="flex flex-col gap-0.5">
                {hours.map((h) => {
                  const isSelected = h === hour;
                  return (
                    <button
                      key={h}
                      type="button"
                      ref={isSelected ? activeHourRef : null}
                      onClick={() => handleSelectHour(h)}
                      className={cn(
                        'w-full py-1.5 rounded-lg text-sm transition-all text-center hover:bg-accent',
                        isSelected
                          ? 'bg-primary text-primary-foreground font-semibold hover:bg-primary/95 shadow-sm'
                          : 'text-foreground'
                      )}
                    >
                      {h}
                    </button>
                  );
                })}
              </div>
            </ScrollArea>

            {/* Minutes scroll container */}
            <ScrollArea className="h-full pr-1">
              <div className="flex flex-col gap-0.5">
                {minutes.map((m) => {
                  const isSelected = m === minute;
                  return (
                    <button
                      key={m}
                      type="button"
                      ref={isSelected ? activeMinuteRef : null}
                      onClick={() => handleSelectMinute(m)}
                      className={cn(
                        'w-full py-1.5 rounded-lg text-sm transition-all text-center hover:bg-accent',
                        isSelected
                          ? 'bg-primary text-primary-foreground font-semibold hover:bg-primary/95 shadow-sm'
                          : 'text-foreground'
                      )}
                    >
                      {m}
                    </button>
                  );
                })}
              </div>
            </ScrollArea>
          </div>
        </PopoverContent>
      </Popover>
    );
  }
);

TimeSelector.displayName = 'TimeSelector';
